// Generate all phones with proper IDs and category assignments
function generatePhones(): Phone[] {
  const allPhones: Phone[] = [];
  
  for (const [brand, phones] of Object.entries(brandPhones)) {
    phones.forEach((p, idx) => {
      const id = `${brand.toLowerCase().replace(/\s+/g, '')}-${String(idx + 1).padStart(3, '0')}`;
      const batteryMah = parseInt(p.specs.battery || '0');
      const categories: string[] = [];
      
      if (batteryMah >= 5000) categories.push('battery');
      if (p.price <= 15000) categories.push('budget');
      if (p.rating >= 4.5 && p.reviews > 1000) categories.push('hot');
      if (p.rating >= 4.3) categories.push('recommended');
      if (p.price <= 10000) categories.push('under10k');
      if (p.price <= 20000) categories.push('under20k');
      if (p.price <= 30000) categories.push('under30k');

      const defaultSpecs: PhoneSpecs = {
        display: p.specs.display || "6.5\" FHD+ LCD",
        processor: p.specs.processor || "Unknown",
        ram: p.specs.ram || "4GB",
        storage: p.specs.storage || "64GB",
        battery: p.specs.battery || "4000mAh",
        charging: p.specs.charging || "10W",
        camera: {
          main: p.specs.camera?.main || "12MP",
          ultrawide: p.specs.camera?.ultrawide || "",
          telephoto: p.specs.camera?.telephoto,
          front: p.specs.camera?.front || "8MP",
        },
        os: p.specs.os || (brand === 'Apple' ? 'iOS 17' : 'Android 14'),
        connectivity: p.specs.connectivity || "4G, WiFi, Bluetooth 5.0",
        dimensions: p.specs.dimensions || "160 x 75 x 8.5 mm",
        weight: p.specs.weight || "185g",
        colors: p.specs.colors || ["Black", "White"],
        waterResistance: p.specs.waterResistance || "None",
        simType: p.specs.simType || "Dual SIM (nano)",
      };

      allPhones.push({
        id,
        name: p.name,
        brand,
        price: p.price,
        originalPrice: p.origPrice,
        image: getPhoneImage(brand, p.price),
        rating: p.rating,
        reviewCount: p.reviews,
        inStock: true,
        stockCount: Math.floor(Math.random() * 25) + 1,
        categories,
        badge: p.badge,
        specs: defaultSpecs,
        deliveryDays: Math.floor(Math.random() * 5) + 2,
      });
    });
  }
  
  return allPhones;
}

export const phones: Phone[] = generatePhones();
